import { createSlice } from '@reduxjs/toolkit';
const collabSlice = createSlice({ name: 'collab', initialState: { messages: [], notifications: [], unreadCount: 0, onlineUsers: [] }, reducers: {
  addMessage: (state, { payload }) => { state.messages.push(payload); },
  addNotification: (state, { payload }) => { state.notifications.unshift(payload); state.unreadCount += 1; },
  setOnlineUsers: (state, { payload }) => { state.onlineUsers = payload; },
} });
export const { addMessage, addNotification, setOnlineUsers } = collabSlice.actions;
export default collabSlice.reducer;
